import numpy as np
import random

class NeuralNetwork:
    def __init__(self, input_size, hidden_sizes, output_size, activations):
        self.input_size = input_size
        self.hidden_sizes = hidden_sizes
        self.output_size = output_size
        self.activations = activations
        self.layers = self.create_layers()
        self.weights = self.initialize_weights()
        self.biases = self.initialize_biases()

    def create_layers(self):
        layers = []
        layers.append(self.input_size)
        layers.extend(self.hidden_sizes)
        layers.append(self.output_size)
        return layers

    def initialize_weights(self):
        weights = []
        for i in range(len(self.layers) - 1):
            weight_matrix = np.random.randn(self.layers[i], self.layers[i+1])
            weights.append(weight_matrix)
        return weights

    def initialize_biases(self):
        biases = []
        for i in range(1, len(self.layers)):
            bias_vector = np.random.randn(self.layers[i])
            biases.append(bias_vector)
        return biases

    def forward_pass(self, X):
        activations = [X]
        for i in range(len(self.layers) - 1):
            z = np.dot(activations[-1], self.weights[i]) + self.biases[i]
            a = self.activate(z, self.activations[i])
            activations.append(a)
        return activations[-1]

    def backward_pass(self, X, y, learning_rate):
        activations = self.forward_pass(X)
        deltas = []
        for i in range(len(self.layers) - 1, 0, -1):
            if i == len(self.layers) - 1:
                delta = (activations[-1] - y) * self.derivative(activations[-1], self.activations[i-1])
            else:
                delta = np.dot(deltas[0], self.weights[i].T) * self.derivative(activations[i], self.activations[i-1])
            deltas.insert(0, delta)

        for i in range(len(self.weights)):
            self.weights[i] -= learning_rate * np.outer(activations[i], deltas[i])
            self.biases[i] -= learning_rate * deltas[i]

    def activate(self, z, activation):
        if activation == 'sigmoid':
            return 1 / (1 + np.exp(-z))
        elif activation == 'relu':
            return np.maximum(0, z)
        elif activation == 'tanh':
            return np.tanh(z)

    def derivative(self, a, activation):
        if activation == 'sigmoid':
            return a * (1 - a)
        elif activation == 'relu':
            return np.where(a > 0, 1, 0)
        elif activation == 'tanh':
            return 1 - a ** 2

# Example usage
input_size = 4
hidden_sizes = [8, 8]
output_size = 3
activations = ['relu', 'relu', 'softmax']

nn = NeuralNetwork(input_size, hidden_sizes, output_size, activations)

# Train the network for regression
X_train = np.random.randn(100, input_size)
y_train = np.random.randn(100, output_size)

for epoch in range(1000):
    for i in range(len(X_train)):
        nn.backward_pass(X_train[i], y_train[i], 0.01)

# Train the network for classification
X_train = np.random.randn(100, input_size)
y_train = np.random.randint(0, output_size, size=(100,))
y_train_one_hot = np.eye(output_size)[y_train]

for epoch in range(1000):
    for i in range(len(X_train)):
        nn.backward_pass(X_train[i], y_train_one_hot[i], 0.01)

