import numpy as np
import math

class Sigmoid:
    def forward(self, x):
        return 1 / (1 + np.exp(-x))

    def backward(self, x):
        return x * (1 - x)

class ReLU:
    def forward(self, x):
        return np.maximum(0, x)

    def backward(self, x):
        return (x > 0).astype(float)

class DenseLayer:
    def __init__(self, input_size, output_size, activation=None):
        self.weights = np.random.randn(input_size, output_size) * np.sqrt(2 / input_size)
        self.biases = np.zeros(output_size)
        self.activation = activation() if activation else None
        self.inputs = None
        self.output = None

    def forward(self, inputs):
        self.inputs = inputs
        self.output = np.dot(inputs, self.weights) + self.biases
        if self.activation:
            self.output = self.activation.forward(self.output)
        return self.output

    def backward(self, grad_output):
        if self.activation:
            grad_output = self.activation.backward(self.output) * grad_output
        grad_weights = np.dot(self.inputs.T, grad_output)
        grad_biases = np.sum(grad_output, axis=0)
        grad_inputs = np.dot(grad_output, self.weights.T)
        return grad_inputs, grad_weights, grad_biases

class NeuralNetwork:
    def __init__(self, input_size, output_size, hidden_sizes, activations=None):
        self.layers = []
        self.activations = activations or [ReLU] * (len(hidden_sizes) - 1) + [Sigmoid]

        for i in range(len(hidden_sizes)):
            if i == 0:
                self.layers.append(DenseLayer(input_size, hidden_sizes[i], self.activations[i]))
            else:
                self.layers.append(DenseLayer(hidden_sizes[i-1], hidden_sizes[i], self.activations[i]))
        self.layers.append(DenseLayer(hidden_sizes[-1], output_size, self.activations[-1]))

    def forward(self, inputs):
        output = inputs
        for layer in self.layers:
            output = layer.forward(output)
        return output

    def backward(self, inputs, targets, learning_rate):
        output = self.forward(inputs)
        grad_output = (output - targets) / len(inputs)

        for layer in reversed(self.layers):
            grad_inputs, grad_weights, grad_biases = layer.backward(grad_output)
            grad_output = grad_inputs

            layer.weights -= learning_rate * grad_weights
            layer.biases -= learning_rate * grad_biases

        return output

