import numpy as np
import math

class Layer:
    def __init__(self, input_size, output_size, activation=None):
        self.weights = np.random.randn(input_size, output_size) * np.sqrt(2 / input_size)
        self.biases = np.zeros((1, output_size))
        self.activation = activation
        self.input = None
        self.output = None
        self.delta = None

    def forward(self, inputs):
        self.input = inputs
        self.output = np.matmul(self.input, self.weights) + self.biases
        if self.activation is not None:
            self.output = self.activation(self.output)
        return self.output

    def backward(self, delta):
        self.delta = delta
        if self.activation is not None:
            self.delta = self.delta * self.activation(self.output, derivative=True)
        input_delta = np.matmul(self.delta, self.weights.T)
        weight_delta = np.matmul(self.input.T, self.delta)
        self.weights -= 0.01 * weight_delta
        self.biases -= 0.01 * np.sum(self.delta, axis=0, keepdims=True)
        return input_delta

class ActivationFunctions:
    @staticmethod
    def sigmoid(x, derivative=False):
        if derivative:
            return x * (1 - x)
        return 1 / (1 + np.exp(-x))

    @staticmethod
    def relu(x, derivative=False):
        if derivative:
            return np.where(x > 0, 1, 0)
        return np.maximum(0, x)

    @staticmethod
    def tanh(x, derivative=False):
        if derivative:
            return 1 - x ** 2
        return np.tanh(x)

class NeuralNetwork:
    def __init__(self, input_size, output_size, hidden_layers=None):
        self.layers = []
        self.layers.append(Layer(input_size, 32, ActivationFunctions.relu))
        if hidden_layers is not None:
            for size in hidden_layers:
                self.layers.append(Layer(32, size, ActivationFunctions.relu))
        self.layers.append(Layer(32 if hidden_layers is None else hidden_layers[-1], output_size))

    def forward(self, inputs):
        for layer in self.layers:
            inputs = layer.forward(inputs)
        return inputs

    def backward(self, targets):
        delta = self.layers[-1].output - targets
        for layer in reversed(self.layers):
            delta = layer.backward(delta)

    def train(self, X, y, epochs=100, batch_size=32):
        for epoch in range(epochs):
            for i in range(0, len(X), batch_size):
                batch_X = X[i:i+batch_size]
                batch_y = y[i:i+batch_size]
                output = self.forward(batch_X)
                self.backward(batch_y)

