import math

class DenseLayer:
    def __init__(self, input_size, output_size, activation=None):
        self.weights = np.random.randn(input_size, output_size) * np.sqrt(2 / input_size)
        self.biases = np.zeros((1, output_size))
        self.activation = activation
        self.input = None
        self.output = None
        self.delta = None

    def forward(self, input_data):
        self.input = input_data
        self.output = np.dot(self.input, self.weights) + self.biases
        if self.activation is not None:
            self.output = self.activation(self.output)
        return self.output

    def backward(self, delta):
        if self.activation is not None:
            delta = delta * self.activation(self.output, derivative=True)
        self.delta = delta
        weight_gradient = np.dot(self.input.T, delta)
        bias_gradient = np.sum(delta, axis=0, keepdims=True)
        return np.dot(delta, self.weights.T), weight_gradient, bias_gradient

class NeuralNetwork:
    def __init__(self, input_size, output_size, hidden_layers=None, activations=None):
        self.layers = []
        if hidden_layers is None:
            hidden_layers = []
        if activations is None:
            activations = [None] * len(hidden_layers)

        self.layers.append(DenseLayer(input_size, hidden_layers[0], activations[0]))
        for i in range(1, len(hidden_layers)):
            self.layers.append(DenseLayer(hidden_layers[i-1], hidden_layers[i], activations[i]))
        self.layers.append(DenseLayer(hidden_layers[-1], output_size, None))

    def forward(self, input_data):
        for layer in self.layers:
            input_data = layer.forward(input_data)
        return input_data

    def backward(self, labels, learning_rate):
        delta = self.layers[-1].output - labels
        for layer in reversed(self.layers):
            delta, weight_gradient, bias_gradient = layer.backward(delta)
            layer.weights -= learning_rate * weight_gradient
            layer.biases -= learning_rate * bias_gradient

