import math

class Layer:
    def __init__(self, n_inputs, n_neurons, activation=None):
        self.weights = np.random.randn(n_inputs, n_neurons) * np.sqrt(2 / n_inputs)
        self.biases = np.zeros((1, n_neurons))
        self.activation = activation
        self.z = None
        self.a = None

    def forward(self, inputs):
        self.z = np.dot(inputs, self.weights) + self.biases
        if self.activation is None:
            self.a = self.z
        else:
            self.a = self.activation(self.z)
        return self.a

    def backward(self, dvalues):
        if self.activation is not None:
            dz = dvalues * self.activation(self.z, True)
        else:
            dz = dvalues
        self.dweights = np.dot(self.a.T, dz)
        self.dbiases = np.sum(dz, axis=0, keepdims=True)
        return np.dot(dz, self.weights.T)

class ActivationReLU:
    @staticmethod
    def forward(z):
        return np.maximum(0, z)

    @staticmethod
    def backward(z, dvalues):
        return (z > 0) * dvalues

class ActivationSigmoid:
    @staticmethod
    def forward(z):
        return 1 / (1 + np.exp(-z))

    @staticmethod
    def backward(z, dvalues):
        output = 1 / (1 + np.exp(-z))
        return output * (1 - output) * dvalues

class ActivationSoftmax:
    @staticmethod
    def forward(z):
        exp_values = np.exp(z - np.max(z, axis=1, keepdims=True))
        return exp_values / np.sum(exp_values, axis=1, keepdims=True)

    @staticmethod
    def backward(z, dvalues):
        jacobian = np.diag(dvalues) - np.expand_dims(dvalues, 1) * np.expand_dims(dvalues, 2)
        return np.dot(jacobian, z.T).T

