import numpy as np
import math

class Layer:
    def __init__(self, n_inputs, n_neurons, activation):
        self.weights = np.random.randn(n_inputs, n_neurons) * np.sqrt(2 / n_inputs)
        self.biases = np.zeros((1, n_neurons))
        self.activation = activation
        self.z = None
        self.a = None
        self.delta = None

    def forward(self, inputs):
        self.z = np.dot(inputs, self.weights) + self.biases
        self.a = self.activation(self.z)
        return self.a

    def backward(self, delta_next, learning_rate):
        self.delta = delta_next @ self.weights.T * self.activation(self.z, derivative=True)
        self.weights -= learning_rate * np.transpose(self.a) @ delta_next
        self.biases -= learning_rate * np.sum(delta_next, axis=0, keepdims=True)
        return self.delta

class Network:
    def __init__(self, input_size, output_size, hidden_layers):
        self.layers = []
        self.layers.append(Layer(input_size, hidden_layers[0], activation=self.sigmoid))
        for i in range(1, len(hidden_layers)):
            self.layers.append(Layer(hidden_layers[i-1], hidden_layers[i], activation=self.sigmoid))
        self.layers.append(Layer(hidden_layers[-1], output_size, activation=self.sigmoid))

    def forward(self, X):
        a = X
        for layer in self.layers:
            a = layer.forward(a)
        return a

    def backward(self, X, y, learning_rate):
        self.forward(X)
        delta = (self.layers[-1].a - y) * self.layers[-1].activation(self.layers[-1].z, derivative=True)
        for layer in reversed(self.layers[:-1]):
            delta = layer.backward(delta, learning_rate)

    def train(self, X, y, epochs, learning_rate):
        for _ in range(epochs):
            self.backward(X, y, learning_rate)

    def sigmoid(self, z, derivative=False):
        if derivative:
            return self.sigmoid(z) * (1 - self.sigmoid(z))
        return 1 / (1 + np.exp(-z))

