import math

class Layer:
    def __init__(self, input_size, output_size, activation):
        self.weights = np.random.randn(output_size, input_size) * np.sqrt(2 / input_size)
        self.biases = np.zeros((output_size, 1))
        self.activation = activation
        self.activation_prime = self.get_activation_prime(activation)
        self.input = None
        self.output = None
        self.delta = None

    def forward(self, input):
        self.input = input
        self.output = self.activation(np.dot(self.weights, self.input) + self.biases)
        return self.output

    def backward(self, delta_next, learning_rate):
        self.delta = np.multiply(delta_next, self.activation_prime(self.input))
        weight_delta = np.dot(self.delta, self.input.T)
        self.weights -= learning_rate * weight_delta
        self.biases -= learning_rate * self.delta
        return np.dot(self.weights.T, self.delta)

    def get_activation_prime(self, activation):
        if activation == 'sigmoid':
            return lambda x: self.sigmoid(x) * (1 - self.sigmoid(x))
        elif activation == 'relu':
            return lambda x: 1. * (x > 0)
        elif activation == 'tanh':
            return lambda x: 1 - self.tanh(x) ** 2
        else:
            raise ValueError("Activation function not supported.")

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def tanh(self, x):
        return np.tanh(x)

