import numpy as np

class Layer:
    def __init__(self, n_inputs, n_neurons, activation=None):
        self.weights = np.random.randn(n_inputs, n_neurons) * np.sqrt(2 / n_inputs)
        self.biases = np.zeros((1, n_neurons))
        self.activation = activation
        self.z = None
        self.a = None

    def forward(self, inputs):
        self.z = np.dot(inputs, self.weights) + self.biases
        if self.activation is None:
            self.a = self.z
        else:
            self.a = self.activation(self.z)
        return self.a

    def backward(self, dvalues):
        m = dvalues.shape[0]
        if self.activation is not None:
            dz = dvalues * self.activation(self.z, derivative=True)
        else:
            dz = dvalues
        self.dweights = np.dot(self.a.T, dz) / m
        self.dbiases = np.sum(dz, axis=0, keepdims=True) / m
        return np.dot(dz, self.weights.T)

class ActivationReLU:
    @staticmethod
    def forward(z):
        return np.maximum(0, z)

    @staticmethod
    def backward(z, derivative=False):
        if derivative:
            return (z > 0).astype(int)
        return ActivationReLU.forward(z)

class ActivationSigmoid:
    @staticmethod
    def forward(z):
        return 1 / (1 + np.exp(-z))

    @staticmethod
    def backward(z, derivative=False):
