class DenseLayer:
    def __init__(self, input_size, output_size, activation):
        self.weights = np.random.randn(input_size, output_size) / np.sqrt(input_size)
        self.biases = np.zeros(output_size)
        self.activation = activation
        self.activation_prime = self.get_activation_prime(activation)

    def forward(self, inputs):
        self.inputs = inputs
        self.outputs = self.activation(np.dot(inputs, self.weights) + self.biases)
        return self.outputs

    def backward(self, grad_outputs):
        grad_inputs = np.dot(grad_outputs, self.weights.T)
        grad_weights = np.dot(self.inputs.T, grad_outputs)
        grad_biases = np.sum(grad_outputs, axis=0)
        return grad_inputs, grad_weights, grad_biases

    def get_activation_prime(self, activation):
        if activation == 'relu':
            return lambda x: np.where(x > 0, 1, 0)
        elif activation == 'sigmoid':
            return lambda x: self.activation(x) * (1 - self.activation(x))
        elif activation == 'tanh':
            return lambda x: 1 - self.activation(x) ** 2
        else:
            raise ValueError('Unsupported activation function.')

