class NeuralNetwork:
    def __init__(self, input_size, hidden_layers, output_size):
        self.input_size = input_size
        self.hidden_layers = hidden_layers
        self.output_size = output_size

        self.weights = []
        self.biases = []

        # Initialize weights and biases
        self.initialize_parameters()

    def initialize_parameters(self):
        for i in range(len(self.hidden_layers) + 1):
            if i == 0:
                W = np.random.randn(self.hidden_layers[i], self.input_size) * np.sqrt(1 / self.input_size)
            elif i == len(self.hidden_layers):
                W = np.random.randn(self.output_size, self.hidden_layers[-1]) * np.sqrt(1 / self.hidden_layers[-1])
            else:
                W = np.random.randn(self.hidden_layers[i], self.hidden_layers[i-1]) * np.sqrt(1 / self.hidden_layers[i-1])
            b = np.zeros((self.hidden_layers[i], 1))
            self.weights.append(W)
            self.biases.append(b)

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def forward(self, X):
        A = X
        self.cache = [A]

        for W, b in zip(self.weights, self.biases):
            Z = np.dot(W, A) + b
            A = self.sigmoid(Z)
            self.cache.append(A)

        return A

    def backward(self, Y, learning_rate):
        m = Y.shape[1]
        dA = -(np.divide(Y, self.cache[-1]) - np.divide(1 - Y, 1 - self.cache[-1]))

        grads = {}
        grads["dA" + str(len(self.weights))] = dA

        for i in range(len(self.weights), 0, -1):
            dZ = np.multiply(grads["dA" + str(i)], self.sigmoid(self.cache[i]) * (1 - self.sigmoid(self.cache[i])))
            dW = np.dot(dZ, self.cache[i-1].T) / m
            db = np.sum(dZ, axis=1, keepdims=True) / m
            grads["dW" + str(i)] = dW
            grads["db" + str(i)] = db

            if i > 1:
                dA = np.dot(self.weights[i-1].T, dZ)
                grads["dA" + str(i-1)] = dA

        for i, (W, b) in enumerate(zip(self.weights, self.biases)):
            W -= learning_rate * grads["dW" + str(i+1)]
            b -= learning_rate * grads["db" + str(i+1)]

    def train(self, X, Y, epochs, learning_rate):
        for epoch in range(epochs):
            Y_pred = self.forward(X)
            self.backward(Y, learning_rate)

            if (epoch+1) % 100 == 0:
                print(f"Epoch [{epoch+1}/{epochs}], Loss: {np.mean(np.square(Y - Y_pred))}")

    def predict(self, X):
        return self.forward(X)

import numpy as np

class DenseLayer:
    def __init__(self, input_size, output_size, activation):
        self.weights = np.random.randn(input_size, output_size) * np.sqrt(2 / input_size)
        self.biases = np.zeros(output_size)
        self.activation = activation
        self.activation_prime = self.get_activation_prime(activation)

    def forward(self, X):
        self.input = X
        self.output = np.dot(X, self.weights) + self.biases
        return self.activation(self.output)

    def backward(self, delta):
        delta_input = np.dot(delta, self.weights.T)
        delta_weights = np.dot(self.input.T, delta)
        delta_biases = np.sum(delta, axis=0)
        return delta_input, delta_weights, delta_biases

    def update(self, learning_rate, delta_weights, delta_biases):
        self.weights -= learning_rate * delta_weights
        self.biases -= learning_rate * delta_biases

    def get_activation_prime(self, activation):
        if activation == 'sigmoid':
            return lambda x: self.sigmoid(x) * (1 - self.sigmoid(x))
        elif activation == 'relu':
            return lambda x: 1. * (x > 0.)
        elif activation == 'tanh':
            return lambda x: 1 - self.tanh(x) ** 2

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def tanh(self, x):
        return np.tanh(x)

