        self.layers = []
        prev_size = input_size
        for hidden_size, activation in zip(hidden_sizes, activations):
            self.layers.append(DenseLayer(prev_size, hidden_size, activation))
            prev_size = hidden_size
        self.layers.append(DenseLayer(prev_size, output_size, 'linear'))

    def forward(self, X):
        for layer in self.layers:
            X = layer.forward(X)
        return X

