        output = self.forward(X)
        delta = (output - y) * self.layers[-1].activation_prime(self.layers[-1].output)
        for layer in reversed(self.layers):
            delta, delta_weights, delta_biases = layer.backward(delta)
            layer.update(learning_rate, delta_weights, delta_biases)

    def train(self, X, y, epochs, learning_rate):
        for _ in range(epochs):
            self.backward(X, y, learning_rate)

