        self.layers = self.create_layers()
        self.weights = self.initialize_weights()
        self.biases = self.initialize_biases()

    def get_activation(self, activation):
        if activation == 'sigmoid':
            return lambda x: 1 / (1 + np.exp(-x))
        elif activation == 'tanh':
            return lambda x: np.tanh(x)
        elif activation == 'relu':
            return lambda x: np.maximum(0, x)
        else:
            raise ValueError('Invalid activation function')

    def create_layers(self):
        layers = [self.input_size]
        layers.extend(self.hidden_sizes)
        layers.append(self.output_size)
        return layers

    def initialize_weights(self):
        weights = []
        for i in range(len(self.layers) - 1):
            weight = np.random.randn(self.layers[i], self.layers[i + 1]) * np.sqrt(2 / self.layers[i])
            weights.append(weight)
        return weights

    def initialize_biases(self):
        biases = []
        for size in self.layers[1:]:
            bias = np.zeros(size)
            biases.append(bias)
        return biases

    def forward(self, X):
        activations = [X]
        for i in range(len(self.layers) - 2):
            z = np.dot(activations[-1], self.weights[i]) + self.biases[i]
            a = self.activation(z)
            activations.append(a)
        z = np.dot(activations[-1], self.weights[-1]) + self.biases[-1]
        output = self.activation(z)
        activations.append(output)
        return activations

    def backward(self, X, y, learning_rate):
        activations = self.forward(X)
        deltas = []
        for i in range(len(self.layers) - 1, 0, -1):
            if i == len(self.layers) - 1:
                delta = (activations[i] - y) * self.activation(activations[i], derivative=True)
            else:
                delta = np.dot(deltas[0], self.weights[i].T) * self.activation(activations[i], derivative=True)
            deltas.insert(0, delta)

        for i in range(len(self.weights)):
            self.weights[i] -= learning_rate * np.dot(activations[i].T, deltas[i])
            self.biases[i] -= learning_rate * np.mean(deltas[i], axis=0)

        return deltas[-1]

