import numpy as np

class NeuronLayer:
    def __init__(self, num_neurons, num_inputs, activation_function):
        self.weights = np.random.randn(num_neurons, num_inputs) * np.sqrt(2 / num_inputs)
        self.biases = np.zeros((num_neurons, 1))
        self.activation_function = activation_function
        self.activation_derivative = self.get_activation_derivative(activation_function)

    def forward(self, inputs):
        self.inputs = inputs
        self.outputs = self.activation_function(np.dot(self.weights, inputs) + self.biases)
        return self.outputs

    def backward(self, doutputs):
        dweights = np.dot(doutputs, self.inputs.T)
        dbiases = np.sum(doutputs, axis=1, keepdims=True)
        dinputs = np.dot(self.weights.T, doutputs)
        return dweights, dbiases, dinputs

    @staticmethod
    def get_activation_derivative(activation_function):
        if activation_function == 'sigmoid':
            return lambda x: x * (1 - x)
        elif activation_function == 'relu':
            return lambda x: 1. * (x > 0)
        else:
            raise ValueError('Invalid activation function')

class NeuralNetwork:
    def __init__(self, layer_sizes, activation_function='sigmoid'):
        self.layers = []
        for i in range(len(layer_sizes) - 1):
            self.layers.append(NeuronLayer(layer_sizes[i+1], layer_sizes[i], activation_function))

    def forward(self, inputs):
        for layer in self.layers:
            inputs = layer.forward(inputs)
        return inputs

    def backward(self, outputs, targets):
        doutputs = 2 * (outputs - targets)
        for layer in reversed(self.layers):
            dweights, dbiases, dinputs = layer.backward(doutputs)
            doutputs = dinputs
        return dweights, dbiases

    def train(self, X, y, epochs, learning_rate):
        for epoch in range(epochs):
            outputs = self.forward(X)
            dweights, dbiases = self.backward(outputs, y)
            for layer, dw, db in zip(self.layers, dweights, dbiases):
                layer.weights -= learning_rate * dw
                layer.biases -= learning_rate * db

