y_train = np.array([[1, 0], [0, 1], [1, 0], [0, 1]])

nn = NeuralNetwork(input_size=2, hidden_layers=[3, 3], output_size=2)
nn.train(X_train, y_train, epochs=10000, learning_rate=0.01)

X_test = np.array([[2, 3], [6, 7]])
y_pred = nn.predict(X_test)
print(y_pred)
